const aliases = {
  BMI: "체질량지수",
  체질량지수: "체질량지수",
};

export function normalizePapsGender(value) {
  const text = String(value || "").trim();
  return text === "여" || text.includes("여") || text.toLowerCase() === "female" ? "여자" : "남자";
}

export function normalizePapsGrade(value) {
  const matched = String(value || "").match(/[1-3]/);
  return matched ? `${matched[0]}학년` : "2학년";
}

export function normalizePapsItemName(value) {
  const text = String(value || "").replace(/\s/g, "");
  return aliases[text] || text;
}

export function evaluatePaps({ grade, gender, itemName, value }) {
  const numeric = Number(value);
  if (!Number.isFinite(numeric)) return null;
  const gradeName = normalizePapsGrade(grade);
  const genderName = normalizePapsGender(gender);
  const normalizedItem = normalizePapsItemName(itemName);
  const matched = PAPS_STANDARD_ROWS.find((row) =>
    row.학년 === gradeName &&
    row.성별 === genderName &&
    normalizePapsItemName(row.평가종목) === normalizedItem &&
    numeric >= Number(row.시작) && numeric <= Number(row.종료)
  );
  if (!matched) return null;
  return {
    score: matched.점수,
    grade: matched.등급,
    gradeLabel: normalizedItem === "체질량지수" ? String(matched.등급) : `${matched.등급}등급`,
    factor: matched.체력요인,
    standardVersion: PAPS_STANDARD_VERSION,
  };
}

export function getPapsUnit(itemName) {
  const name = normalizePapsItemName(itemName);
  if (["왕복오래달리기","윗몸말아올리기","(무릎대고)팔굽혀펴기"].includes(name)) return "회";
  if (["50m달리기","오래달리기걷기","스텝검사"].includes(name)) return "초";
  if (["악력"].includes(name)) return "kg";
  if (["앉아윗몸앞으로굽히기","제자리멀리뛰기","종합유연성"].includes(name)) return "cm";
  return "";
}
